import { DetectorConfigResp } from "src/app/generated-protos/detector-config-msgs";
import { ContextImageScanModelGenerator } from "./context-image-scan-model-generator";
import { ScanItem } from "src/app/generated-protos/scan";


describe("scanModelGenerator", () => {
  it("should calculate", () => {
    const gen = new ContextImageScanModelGenerator();

    // Taken from sol 257 Dourbes scan so we have a lot of points:
    const imgName = "089063943/PCCR0257_0689789827_000VIS_N008000008906394300060LUD01.tif";
    const mdl = gen.processBeamData(
      imgName,
      ScanItem.create(dourbes),
      dourbesEntries,
      dourbesXYZ,
      2,
      dourbesIJs,
      DetectorConfigResp.create(detectorConfig),
    );

    expect(mdl.imageName).toEqual(imgName);
  });
});

